class Solution {
    public int findNumberOfLIS(int[] nums) {
        int n = nums.length;
        int[] dp = new int[n];
        int[] maxLen = new int[n];
        for (int i = 0; i < n; i++) {
            maxLen[i] = 1;
            dp[i] = 1;
        }
        int maxLength = 1;
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j]) {
                    if (maxLen[j] + 1 > maxLen[i]) {
                        maxLen[i] = maxLen[j] + 1;
                        dp[i] = dp[j];
                    } else if (maxLen[j] + 1 == maxLen[i]) {
                        dp[i] += dp[j];
                    }
                }
            }
            maxLength = Math.max(maxLength, maxLen[i]);
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (maxLen[i] == maxLength) {
                count += dp[i];
            }
        }
        return count;
    }
}
